import { expect, test as base, vi } from "vitest";
import { act } from "react";
import { createRoot, type Root } from "react-dom/client";
import { userEvent } from "@vitest/browser/context";
import type { UpdateProfileResult } from "./profile-edit.action";
import { ProfileEditPresenter } from "./profile-edit.presenter.form.client";

(globalThis as { IS_REACT_ACT_ENVIRONMENT?: boolean }).IS_REACT_ACT_ENVIRONMENT = true;

const editProfileMock = vi.fn<(nickname: string, introduce: string) => Promise<UpdateProfileResult>>();

vi.mock("./profile-edit.action", () => ({
  editProfile: (nickname: string, introduce: string) => editProfileMock(nickname, introduce),
}));

type Ctx = { container: HTMLElement; root: Root };

const test = base.extend<{ ctx: Ctx }>({
  ctx: async ({}, provide) => {
    editProfileMock.mockReset();
    const container = document.createElement("div");
    document.body.appendChild(container);
    const root = createRoot(container);

    await provide({ container, root });

    await act(async () => {
      root.unmount();
    });
    container.remove();
  },
});

async function render(ctx: Ctx, element: React.ReactElement) {
  await act(async () => {
    ctx.root.render(element);
  });
}

test("初期値が入力欄に表示される", async ({ ctx }) => {
  await render(
    ctx,
    <ProfileEditPresenter defaultNickname="taro" defaultIntroduce="hello" />,
  );

  const nickname = ctx.container.querySelector<HTMLInputElement>("#nickname");
  const introduce = ctx.container.querySelector<HTMLTextAreaElement>("#introduce");
  expect(nickname?.value).toBe("taro");
  expect(introduce?.value).toBe("hello");
});

test("空のニックネームで blur すると必須エラーが表示される", async ({ ctx }) => {
  await render(ctx, <ProfileEditPresenter defaultNickname="taro" />);

  const nickname = ctx.container.querySelector<HTMLInputElement>("#nickname")!;
  await userEvent.fill(nickname, "");
  await userEvent.tab();

  await vi.waitFor(() => {
    expect(ctx.container.textContent).toContain("ニックネームは必須です");
  });
});

test("送信成功時に成功メッセージが表示される", async ({ ctx }) => {
  editProfileMock.mockResolvedValue({ success: true });
  await render(ctx, <ProfileEditPresenter defaultNickname="taro" defaultIntroduce="hi" />);

  const form = ctx.container.querySelector("form")!;
  await act(async () => {
    form.requestSubmit();
  });

  await vi.waitFor(() => {
    expect(editProfileMock).toHaveBeenCalledWith("taro", "hi");
    expect(ctx.container.textContent).toContain("プロフィールを保存しました");
  });
});

test("送信失敗時にエラーメッセージが表示される", async ({ ctx }) => {
  editProfileMock.mockResolvedValue({ success: false, message: "更新失敗" });
  await render(ctx, <ProfileEditPresenter defaultNickname="taro" />);

  const form = ctx.container.querySelector("form")!;
  await act(async () => {
    form.requestSubmit();
  });

  await vi.waitFor(() => {
    expect(ctx.container.textContent).toContain("更新失敗");
    expect(ctx.container.textContent).not.toContain("プロフィールを保存しました");
  });
});

test("disabled=true のときは入力欄と送信ボタンが無効化される", async ({ ctx }) => {
  await render(ctx, <ProfileEditPresenter disabled />);

  const nickname = ctx.container.querySelector<HTMLInputElement>("#nickname")!;
  const introduce = ctx.container.querySelector<HTMLTextAreaElement>("#introduce")!;
  const submit = ctx.container.querySelector<HTMLButtonElement>("button[type='submit']")!;
  expect(nickname.disabled).toBe(true);
  expect(introduce.disabled).toBe(true);
  expect(submit.disabled).toBe(true);
});

