import { expect, test as base } from "vitest";
import { act } from "react";
import { createRoot, type Root } from "react-dom/client";
import { useIsHydrated } from "./use-is-hydrated";

(globalThis as { IS_REACT_ACT_ENVIRONMENT?: boolean }).IS_REACT_ACT_ENVIRONMENT = true;

function HydrationProbe() {
  const hydrated = useIsHydrated();
  return <span data-testid="hydration-state">{hydrated ? "yes" : "no"}</span>;
}

const test = base.extend<{ mount: { container: HTMLElement; root: Root } }>({
  mount: async ({}, provide) => {
    const container = document.createElement("div");
    document.body.appendChild(container);
    const root = createRoot(container);

    await provide({ container, root });

    await act(async () => {
      root.unmount();
    });
    container.remove();
  },
});

test("useIsHydrated: マウント後に true を返す", async ({ mount }) => {
  await act(async () => {
    mount.root.render(<HydrationProbe />);
  });

  const node = mount.container.querySelector("[data-testid='hydration-state']");
  expect(node?.textContent).toBe("yes");
});

