import { expect, test as base, vi } from "vitest";

const getSessionMock = vi.fn<() => Promise<{ data: { session: unknown } }>>();

vi.mock("@/lib/supabase/server", () => ({
  createClient: async () => ({
    auth: { getSession: getSessionMock },
  }),
}));

const test = base.extend<{ getProfile: typeof import("./profile.data").getProfile }>({
  getProfile: async ({}, provide) => {
    getSessionMock.mockReset();
    vi.unstubAllGlobals();
    vi.unstubAllEnvs();
    vi.stubEnv("API_URL", "https://api.test.example");
    const { getProfile } = await import("./profile.data");
    await provide(getProfile);
  },
});

test("session が無い場合は UNAUTHORIZED コードを返す", async ({ getProfile }) => {
  getSessionMock.mockResolvedValue({ data: { session: null } });

  const result = await getProfile();

  expect(result).toEqual({ success: false, code: "UNAUTHORIZED" });
});

test("API が 200 以外を返した場合は FETCH_FAILED コードを返す", async ({ getProfile }) => {
  getSessionMock.mockResolvedValue({
    data: {
      session: { user: { id: "user-1" }, access_token: "token-1" },
    },
  });
  vi.stubGlobal(
    "fetch",
    vi.fn(async () => new Response(null, { status: 500 })),
  );

  const result = await getProfile();

  expect(result).toEqual({ success: false, code: "FETCH_FAILED" });
});

test("API が 200 を返した場合は Profile を返す", async ({ getProfile }) => {
  getSessionMock.mockResolvedValue({
    data: {
      session: { user: { id: "user-1" }, access_token: "token-1" },
    },
  });
  const fetchMock = vi.fn(
    async () =>
      new Response(JSON.stringify({ nickname: "taro", introduce: "hi" }), {
        status: 200,
        headers: { "Content-Type": "application/json" },
      }),
  );
  vi.stubGlobal("fetch", fetchMock);

  const result = await getProfile();

  expect(result).toEqual({
    success: true,
    profile: { nickname: "taro", introduce: "hi" },
  });
  expect(fetchMock).toHaveBeenCalledWith(
    "https://api.test.example/v1/users/user-1",
    { headers: { Authorization: "Bearer token-1" } },
  );
});

